// StrictServerInterface represents all server handlers.
type StrictServerInterface interface {
	// Bulk operations
	// (POST /_bulk)
	Bulk(ctx context.Context, request BulkRequestObject) (BulkResponseObject, error)
	// Cluster health in plain text table format
	// (GET /_cat/health)
	CatHealth(ctx context.Context, request CatHealthRequestObject) (CatHealthResponseObject, error)
	// List indices in plain text table format
	// (GET /_cat/indices)
	CatIndices(ctx context.Context, request CatIndicesRequestObject) (CatIndicesResponseObject, error)
	// Delete an index
	// (DELETE /{index})
	DeleteIndex(ctx context.Context, request DeleteIndexRequestObject) (DeleteIndexResponseObject, error)
	// Get index metadata
	// (GET /{index})
	GetIndex(ctx context.Context, request GetIndexRequestObject) (GetIndexResponseObject, error)
	// Create an index
	// (PUT /{index})
	CreateIndex(ctx context.Context, request CreateIndexRequestObject) (CreateIndexResponseObject, error)
	// Bulk operations with index scope
	// (POST /{index}/_bulk)
	BulkWithIndex(ctx context.Context, request BulkWithIndexRequestObject) (BulkWithIndexResponseObject, error)
	// Delete a document
	// (DELETE /{index}/_doc/{id})
	DeleteDocument(ctx context.Context, request DeleteDocumentRequestObject) (DeleteDocumentResponseObject, error)
	// Get a document
	// (GET /{index}/_doc/{id})
	GetDocument(ctx context.Context, request GetDocumentRequestObject) (GetDocumentResponseObject, error)
	// Index a document (POST)
	// (POST /{index}/_doc/{id})
	IndexDocumentPost(ctx context.Context, request IndexDocumentPostRequestObject) (IndexDocumentPostResponseObject, error)
	// Index a document (PUT)
	// (PUT /{index}/_doc/{id})
	IndexDocumentPut(ctx context.Context, request IndexDocumentPutRequestObject) (IndexDocumentPutResponseObject, error)
	// Refresh an index
	// (POST /{index}/_refresh)
	Refresh(ctx context.Context, request RefreshRequestObject) (RefreshResponseObject, error)
	// Search documents (GET)
	// (GET /{index}/_search)
	SearchGet(ctx context.Context, request SearchGetRequestObject) (SearchGetResponseObject, error)
	// Search documents (POST)
	// (POST /{index}/_search)
	SearchPost(ctx context.Context, request SearchPostRequestObject) (SearchPostResponseObject, error)
}

type StrictHandlerFunc = strictnethttp.StrictHTTPHandlerFunc
type StrictMiddlewareFunc = strictnethttp.StrictHTTPMiddlewareFunc

type StrictHTTPServerOptions struct {
	RequestErrorHandlerFunc  func(w http.ResponseWriter, r *http.Request, err error)
	ResponseErrorHandlerFunc func(w http.ResponseWriter, r *http.Request, err error)
}

func NewStrictHandler(ssi StrictServerInterface, middlewares []StrictMiddlewareFunc) ServerInterface {
	return &strictHandler{ssi: ssi, middlewares: middlewares, options: StrictHTTPServerOptions{
		RequestErrorHandlerFunc: func(w http.ResponseWriter, r *http.Request, err error) {
			http.Error(w, err.Error(), http.StatusBadRequest)
		},
		ResponseErrorHandlerFunc: func(w http.ResponseWriter, r *http.Request, err error) {
			http.Error(w, err.Error(), http.StatusInternalServerError)
		},
	}}
}

func NewStrictHandlerWithOptions(ssi StrictServerInterface, middlewares []StrictMiddlewareFunc, options StrictHTTPServerOptions) ServerInterface {
	return &strictHandler{ssi: ssi, middlewares: middlewares, options: options}
}

type strictHandler struct {
	ssi         StrictServerInterface
	middlewares []StrictMiddlewareFunc
	options     StrictHTTPServerOptions
}

// Bulk operation middleware
func (sh *strictHandler) Bulk(w http.ResponseWriter, r *http.Request) {
	var request BulkRequestObject

	request.Body = r.Body

	handler := func(ctx context.Context, w http.ResponseWriter, r *http.Request, request interface{}) (interface{}, error) {
		return sh.ssi.Bulk(ctx, request.(BulkRequestObject))
	}
	for _, middleware := range sh.middlewares {
		handler = middleware(handler, "Bulk")
	}

	response, err := handler(r.Context(), w, r, request)

	if err != nil {
		sh.options.ResponseErrorHandlerFunc(w, r, err)
	} else if validResponse, ok := response.(BulkResponseObject); ok {
		if err := validResponse.VisitBulkResponse(w); err != nil {
			sh.options.ResponseErrorHandlerFunc(w, r, err)
		}
	} else if response != nil {
		sh.options.ResponseErrorHandlerFunc(w, r, fmt.Errorf("unexpected response type: %T", response))
	}
}

